package user;

option java_multiple_files = true;
option java_package = "com.maum.backend.protobuf.user";

service UserService {
  rpc GetUser(GetUserRequest) returns (GetUserResponse);
  rpc UpdateProfile(UpdateProfileRequest) returns (UpdateProfileResponse);
  rpc ListUsers(ListUsersRequest) returns (ListUsersResponse);
}

message GetUserRequest {
  string user_id = 1;
}

message GetUserResponse {
  User user = 1;
}

message UpdateProfileRequest {
  string user_id = 1;
  string nickname = 2;
  string bio = 3;
  string profile_image_url = 4;
  int32 age = 5;
  string gender = 6;
  string location = 7;
}

message UpdateProfileResponse {
  User user = 1;
}

message User {
  string id = 1;
  string nickname = 2;
  string bio = 3;
  string profile_image_url = 4;
  int32 age = 5;
  string gender = 6;
  string location = 7;
  string created_at = 8;
  string updated_at = 9;
}

message ListUsersRequest {
  int32 limit = 1;
  int32 offset = 2;
}

message ListUsersResponse {
  repeated User users = 1;
}
```

#### gRPC Service 구현 (user/src/main/kotlin/com/maum/backend/controller/)

```kotlin
@GrpcService
class UserGrpcService(
    private val userService: UserService,
) : UserServiceGrpc.UserServiceImplBase() {

    override fun getUser(
        request: GetUserRequest,
        responseObserver: StreamObserver<GetUserResponse>,
    ) {
        try {
            val user = userService.getUser(request.userId)
            val response = GetUserResponse.newBuilder()
                .setUser(user.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: NotFoundException) {
            responseObserver.onError(
                Status.NOT_FOUND
                    .withDescription(e.message)
                    .asRuntimeException()
            )
        }
    }

    override fun updateProfile(
        request: UpdateProfileRequest,
        responseObserver: StreamObserver<UpdateProfileResponse>,
    ) {
        try {
            val user = userService.updateProfile(
                userId = request.userId,
                nickname = request.nickname,
                bio = request.bio,
                profileImageUrl = request.profileImageUrl,
                age = request.age,
                gender = request.gender,
                location = request.location,
            )
            val response = UpdateProfileResponse.newBuilder()
                .setUser(user.toProto())
                .build()
            responseObserver.onNext(response)
            responseObserver.onCompleted()
        } catch (e: Exception) {
            responseObserver.onError(
                Status.INTERNAL
                    .withDescription("프로필 업데이트 실패")
                    .asRuntimeException()
            )
        }
    }
}
```

#### User Service 비즈니스 로직 (user/src/main/kotlin/com/maum/backend/service/)

```kotlin
@Service
class UserService(
    private val userRepository: UserRepository,
) {
    @Transactional(readOnly = true)
    fun getUser(userId: String): UserEntity {
        return userRepository.findById(userId)
            .orElseThrow { NotFoundException("사용자를 찾을 수 없습니다: $userId") }
    }

    @Transactional
    fun updateProfile(
        userId: String,
        nickname: String? = null,
        bio: String? = null,
        profileImageUrl: String? = null,
        age: Int? = null,
        gender: String? = null,
        location: String? = null,
    ): UserEntity {
        val user = getUser(userId)

        nickname?.let { user.nickname = it }
        bio?.let { user.bio = it }
        profileImageUrl?.let { user.profileImageUrl = it }
        age?.let { user.age = it }
        gender?.let { user.gender = it }
        location?.let { user.location = it }

        return userRepository.save(user)
    }
}
```

